from pathlib import Path
matches=[]
for p in Path('backend-hormonia').rglob('*'):
    if p.is_file() and p.suffix in {'.py','.env','.example','.yml','.yaml','.md','.ini'}:
        try: txt=p.read_text(errors='ignore')
        except: continue
        if 'sslmin' in txt.lower() or 'ssl_min' in txt.lower() or 'sslmode' in txt.lower():
            for i,line in enumerate(txt.splitlines(),1):
                if 'sslmin' in line.lower() or 'ssl_min' in line.lower() or 'sslmode' in line.lower():
                    matches.append(f'{p}:{i}:{line[:180]}')
for m in matches[:80]: print(m)
print('total',len(matches))
